prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(CONTAINS(STR(?normId), "3c08e52742754da6a4065fc5787131dc") || CONTAINS(STR(?origId), "3c08e52742754da6a4065fc5787131dc"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?flow ?flowName ?source ?target WHERE {
  ?choreo a bboExt:Choreography .
  FILTER(STRENDS(STR(?choreo), "sid_86d8a78f_54c4_423d_92e1_edf43db849dc"))
  ?flow a bbo:SequenceFlow .
  ?flow tai:belongsTo ?choreo .
  OPTIONAL { ?flow bbo:name ?flowName . }
  OPTIONAL { ?flow bbo:has_sourceRef ?source . }
  OPTIONAL { ?flow bbo:has_targetRef ?target . }
}
LIMIT 50
